{
 "level": "A2–B1",
 "intro": "In this topic you will learn to <strong>choose between will and be going to</strong> depending on whether it is a spontaneous decision, a ready-made plan, a thought or a prediction with a visible proof.",
 "rules": [
 {
 "label": "WILL",
 "color": "blue",
 "text": "<strong>Decision now, promise, offer, opinion</strong>:",
 "example": "I'll get some milk. I think they will win. Look at those clouds! Quick Comparison"
 },
 {
 "label": "BE GOING TO",
 "color": "emerald",
 "text": "Use the pattern in the examples and focus on the highlighted words.",
 "example": "We're going to visit Lisbon. / Look at those clouds!"
 },
 {
 "label": "KEY QUESTION",
 "color": "amber",
 "text": "Use the pattern in the examples and focus on the highlighted words.",
 "example": "now / already planned / evidence"
 }
 ]
}

{
 "title": "1. Quick comparison",
 "intro": "Here is the main difference between the two forms:",
 "rows": [
 {
 "en": "Will + V1",
 "ua": "Will + V1",
 "note": "We're out of milk. — I'll buy some."
 },
 {
 "en": "Be going to + V1",
 "ua": "Be going to + V1",
 "note": "I'm going to buy some after work."
 },
 {
 "en": "Will + V1",
 "ua": "Will + V1",
 "note": "I think she will come."
 },
 {
 "en": "Be going to + V1",
 "ua": "Be going to + V1",
 "note": "Look at those clouds. It's going to rain."
 },
 {
 "en": "Will + V1",
 "ua": "Will + V1",
 "note": "I'll help you. / Will you open the window?"
 }
 ],
 "warning": "💡 Both forms talk about the future, but convey different logic of the speaker."
}

{
 "title": "2. Formulas",
 "intro": "Compare the main structures of affirmation, negation and question:",
 "items": [
 {
 "label": "Will",
 "title": "Affirmative",
 "subtitle": "Subject + will + V1: I will call you."
 },
 {
 "label": "Won't",
 "title": "Negative",
 "subtitle": "Subject + will not + V1: She won't be late."
 },
 {
 "label": "Will...?",
 "title": "Question",
 "subtitle": "Will + subject + V1? will you come? not/isn't/aren't going to + V1."
 },
 {
 "label": "Going to",
 "title": "Affirmative",
 "subtitle": "Subject + am/is/are going to + V1: We are going to move."
 },
 {
 "label": "Not going to",
 "title": "Negative",
 "subtitle": "Subject + am not/isn't/aren't going to + V1."
 },
 {
 "label": "Are... going to?",
 "title": "Question",
 "subtitle": "Am/Is/Are + subject + going to + V1?"
 }
 ]
}

{
 "title": "3. When to Use will I'll answer it.",
 "sections": [
 {
 "label": "A spontaneous decision",
 "color": "blue",
 "description": "Use the pattern in the examples and focus on the highlighted words.",
 "examples": [
 {
 "en": "The phone is ringing. I'll answer it.",
 "ua": "The phone is ringing. I'll answer it."
 },
 {
 "en": "You look tired. I'll make some tea.",
 "ua": "You look tired. I'll make some tea."
 },
 {
 "en": "We have no bread. I'll go to the shop.",
 "ua": "We have no bread. I'll go to the shop."
 }
 ]
 },
 {
 "label": "Opinion or assumption",
 "color": "emerald",
 "description": "For an <strong>opinion, prediction, or assumption</strong> without direct evidence, we often use <strong>will</strong>.",
 "examples": [
 {
 "en": "I think the Conservatives will win.",
 "ua": "I think the Conservatives will win."
 },
 {
 "en": "I don't think she will arrive. we typically use <strong>will</strong>.",
 "ua": "I don't think she will arrive. we typically use <strong>will</strong>."
 },
 {
 "en": "You'll love this movie.",
 "ua": "You'll love this movie."
 }
 ]
 },
 {
 "label": "Promises, offers, and requests",
 "color": "amber",
 "description": "Use the pattern in the examples and focus on the highlighted words.",
 "examples": [
 {
 "en": "I'll help you tomorrow.",
 "ua": "I'll help you tomorrow."
 },
 {
 "en": "Will you close the door, please?",
 "ua": "Will you close the door, please?"
 },
 {
 "en": "I won't tell anyone.",
 "ua": "I won't tell anyone."
 }
 ],
 "note": "📌 We also often use <strong>will</strong> for future facts: <em>The sun will rise tomorrow.</em>"
 }
 ]
}

{
 "title": "4. To use be going to July.",
 "sections": [
 {
 "label": "A plan or intention",
 "color": "emerald",
 "description": "Use the pattern in the examples and focus on the highlighted words.",
 "examples": [
 {
 "en": "We're going to visit Lisbon in July.",
 "ua": "We're going to visit Lisbon in July."
 },
 {
 "en": "I'm going to study at a different university next year.",
 "ua": "I'm going to study at a different university next year."
 },
 {
 "en": "She's going to stay in tonight.",
 "ua": "She's going to stay in tonight."
 }
 ]
 },
 {
 "label": "Prediction with evidence",
 "color": "blue",
 "description": "When we <strong>see a sign or evidence now</strong>, it is more natural to use <strong>be going to</strong>.",
 "examples": [
 {
 "en": "Look at those clouds. It's going to rain.",
 "ua": "Look at those clouds. It's going to rain."
 },
 {
 "en": "He's driving too fast. He's going to have an accident.",
 "ua": "He's driving too fast. He's going to have an accident."
 },
 {
 "en": "The glass is near the edge. It's going to fall.",
 "ua": "The glass is near the edge. It's going to fall."
 }
 ]
 },
 {
 "label": "Questions about plans",
 "color": "amber",
 "description": "When we want to know about <strong>someone's intention or organized plan</strong>, we often ask through <strong>be going to</strong>.",
 "examples": [
 {
 "en": "What are you going to do after the lesson?",
 "ua": "What are you going to do after the lesson?"
 },
 {
 "en": "Are you going to drive to work today?",
 "ua": "Are you going to drive to work today?"
 },
 {
 "en": "Where are they going to stay?",
 "ua": "Where are they going to stay?"
 }
 ]
 }
 ]
}

{
 "title": "5. Parallel examples",
 "intro": "Similar situations, but different content of the form:",
 "rows": [
 {
 "en": "There's no milk. — I'll buy some.",
 "ua": "There's no milk. — I'll buy some.",
 "note": "spontaneous reaction"
 },
 {
 "en": "I know. I'm going to buy some later.",
 "ua": "I know. I'm going to buy some later.",
 "note": "prior intention"
 },
 {
 "en": "I think they will win.",
 "ua": "I think they will win.",
 "note": "prediction based on opinion"
 },
 {
 "en": "They are going to win. They already have most of the votes.",
 "ua": "They are going to win. They already have most of the votes.",
 "note": "prediction based on evidence"
 }
 ],
 "warning": "💡 The same future event can be described differently if the reason for choosing the form changes."
}

{
 "title": "6. Typical mistakes",
 "items": [
 "We don't say <strong>will to buy</strong>. After <strong>will</strong> you need a <strong>base form without to</strong>: <em>will buy</em>.",
 "Do not omit the verb <strong>be</strong> in the construction <strong>going to</strong>: correctly <em>I am going to go</em>, not <em>I going to go</em>.",
 "Do not confuse <strong>thought</strong> and <strong>visible evidence</strong>: <em>I think it will rain</em> vs <em>Look at the sky. It's going to rain. Short selection algorithm",
 "Use the pattern in the examples."
 ]
}

{
 "title": "7. A quick choice algorithm",
 "items": [
 "The decision occurred <strong>right now</strong> → choose <strong>will</strong>.",
 "The plan or intention was <strong>even before the moment of speech</strong> → choose <strong>be going to</strong>.",
 "It is a <strong>promise, offer, request</strong> → usually <strong>will</strong>.",
 "It is <strong>an opinion, assumption, prediction without proof</strong> → more often <strong>will</strong>.",
 "There is <strong>visible proof or a situation in front of the eyes</strong> → more often <strong>be going to</strong>."
 ]
}

